class Solution {
public:
    void dfs(int r, int c, int rows, int cols, vector<vector<int>>& grid) {
        if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] == 0)
            return;

        grid[r][c] = 0; // mark visited

        dfs(r + 1, c, rows, cols, grid);
        dfs(r - 1, c, rows, cols, grid);
        dfs(r, c + 1, rows, cols, grid);
        dfs(r, c - 1, rows, cols, grid);
    }

    int countEnclavedLandCells(
        vector<vector<int>>& landSeaGrid,
        int gridRowCount,
        vector<int>& gridColumnSizes
    ) {
        int rows = gridRowCount;
        int cols = gridColumnSizes[0];

        // Remove boundary-connected land
        for (int i = 0; i < rows; i++) {
            dfs(i, 0, rows, cols, landSeaGrid);
            dfs(i, cols - 1, rows, cols, landSeaGrid);
        }

        for (int j = 0; j < cols; j++) {
            dfs(0, j, rows, cols, landSeaGrid);
            dfs(rows - 1, j, rows, cols, landSeaGrid);
        }

        // Count enclosed land cells
        int ans = 0;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (landSeaGrid[i][j] == 1)
                    ans++;
            }
        }
        return ans;
    }
};

