#include <stdio.h>
#include <stdlib.h>

// Helper function to perform DFS and mark boundary-connected land cells as visited (0)
void dfs(int** grid, int r, int c, int rows, int cols) {
    // Boundary checks and check if the current cell is land (1)
    if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] != 1) {
        return;
    }

    // Mark the current land cell as sea (0) so it's not counted, 
    // and to prevent infinite loops in DFS
    grid[r][c] = 0;

    // Visit all 4 adjacent directions (up, down, left, right)
    dfs(grid, r + 1, c, rows, cols);
    dfs(grid, r - 1, c, rows, cols);
    dfs(grid, r, c + 1, rows, cols);
    dfs(grid, r, c - 1, rows, cols);
}

// Main function to count the enclosed land cells
int countEnclavedLandCells(int** landSeaGrid, int gridRowCount, int* gridColumnSizes) {
    if (gridRowCount == 0) return 0;

    // Assuming all rows have the same number of columns
    int gridColCount = gridColumnSizes[0]; 

    // Step 1: Traverse the top and bottom boundaries
    for (int j = 0; j < gridColCount; j++) {
        if (landSeaGrid[0][j] == 1) {
            dfs(landSeaGrid, 0, j, gridRowCount, gridColCount);
        }
        if (landSeaGrid[gridRowCount - 1][j] == 1) {
            dfs(landSeaGrid, gridRowCount - 1, j, gridRowCount, gridColCount);
        }
    }

    // Step 2: Traverse the left and right boundaries
    for (int i = 0; i < gridRowCount; i++) {
        if (landSeaGrid[i][0] == 1) {
            dfs(landSeaGrid, i, 0, gridRowCount, gridColCount);
        }
        if (landSeaGrid[i][gridColCount - 1] == 1) {
            dfs(landSeaGrid, i, gridColCount - 1, gridRowCount, gridColCount);
        }
    }

    // Step 3: Count the remaining 1s, which are completely surrounded by 0s
    int enclavedCount = 0;
    for (int i = 0; i < gridRowCount; i++) {
        for (int j = 0; j < gridColCount; j++) {
            if (landSeaGrid[i][j] == 1) {
                enclavedCount++;
            }
        }
    }

    return enclavedCount;
}

