class Solution {
    countEnclavedLandCells(landSeaGrid, gridRowCount, gridColumnSizes) {
        const rows = gridRowCount;
        const cols = gridColumnSizes[0];

        const queue = [];
        const dirs = [[1,0], [-1,0], [0,1], [0,-1]];

        // Push all boundary land cells into queue
        for (let i = 0; i < rows; i++) {
            if (landSeaGrid[i][0] === 1) {
                queue.push([i, 0]);
                landSeaGrid[i][0] = 0;
            }
            if (landSeaGrid[i][cols - 1] === 1) {
                queue.push([i, cols - 1]);
                landSeaGrid[i][cols - 1] = 0;
            }
        }

        for (let j = 0; j < cols; j++) {
            if (landSeaGrid[0][j] === 1) {
                queue.push([0, j]);
                landSeaGrid[0][j] = 0;
            }
            if (landSeaGrid[rows - 1][j] === 1) {
                queue.push([rows - 1, j]);
                landSeaGrid[rows - 1][j] = 0;
            }
        }

        // BFS flood-fill
        let head = 0;
        while (head < queue.length) {
            const [r, c] = queue[head++];

            for (const [dr, dc] of dirs) {
                const nr = r + dr;
                const nc = c + dc;

                if (nr >= 0 && nc >= 0 && nr < rows && nc < cols && landSeaGrid[nr][nc] === 1) {
                    landSeaGrid[nr][nc] = 0;
                    queue.push([nr, nc]);
                }
            }
        }

        // Count remaining land cells
        let enclaves = 0;
        for (let i = 0; i < rows; i++) {
            for (let j = 0; j < cols; j++) {
                if (landSeaGrid[i][j] === 1)
                    enclaves++;
            }
        }

        return enclaves;
    }
}
